<?php
header('Content-Type: application/json; charset=utf-8');require_once __DIR__.'/../config.php';
if(!isset($_SESSION['userId'])||strtolower((string)($_SESSION['userRole']??''))!=='admin'){http_response_code(403);echo json_encode(['success'=>false,'message'=>'Administrator access required']);exit;}
ensureSalaryScalesTable($conn);$p=json_decode(file_get_contents('php://input'),true)?:[];$action=strtolower(trim((string)($p['action']??'save')));$id=(int)($p['salary_scale_id']??0);
if($action==='delete'){if($id<1){echo json_encode(['success'=>false,'message'=>'Invalid scale']);exit;}$s=$conn->prepare('DELETE FROM tb_salary_scales WHERE salary_scale_id=?');$s->bind_param('i',$id);$ok=$s->execute();echo json_encode(['success'=>$ok,'message'=>$ok?'Salary scale deleted.':'Unable to delete scale.']);exit;}
$code=strtoupper(trim((string)($p['scale_code']??'')));$description=trim((string)($p['description']??''));$order=max(0,(int)($p['sort_order']??0));$active=(!isset($p['is_active'])||filter_var($p['is_active'],FILTER_VALIDATE_BOOL))?1:0;if($code===''){echo json_encode(['success'=>false,'message'=>'Scale code is required']);exit;}
if($id>0){$s=$conn->prepare('UPDATE tb_salary_scales SET scale_code=?,description=?,sort_order=?,is_active=?,updated_at=NOW() WHERE salary_scale_id=?');$s->bind_param('ssiii',$code,$description,$order,$active,$id);}else{$s=$conn->prepare('INSERT INTO tb_salary_scales(scale_code,description,sort_order,is_active) VALUES(?,?,?,?)');$s->bind_param('ssii',$code,$description,$order,$active);}$ok=$s->execute();echo json_encode(['success'=>$ok,'message'=>$ok?'Salary scale saved.':'Unable to save salary scale.']);
